import React, { useEffect, useState } from 'react';
import HotTemplate from './HotTemplate';
import axios from 'axios';

const HotForYou = () => {
    const [menuItems, setMenuItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const title = "Hot For You";
    const subtitle = "Aanbevolen items om toe te voegen aan jouw menu.";

    const idealCounts = {
        Beer: 11,
        Cocktail: 8,
        Coffee: 4,
        Juices: 5,
        Mocktails: 7,
        'Soft Drinks': 6,
        Spirits: 3,
        'Sport/Energy Drinks': 4,
        'Tea & Infusions': 5,
        Wine: 4
    };

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [countsRes, itemsRes] = await Promise.all([
                    axios.get('http://localhost:3007/api/menu-counts', { withCredentials: true }),
                    axios.get('http://localhost:3007/api/items-not-on-menu', { withCredentials: true }),
                ]);

                // Categorieën die onderbezet zijn
                const countsByCategory = countsRes.data.reduce((acc, { category, count_on_menu }) => {
                    acc[category] = count_on_menu;
                    return acc;
                }, {});

                const missingCategories = new Set(
                    Object.entries(idealCounts)
                        .filter(([cat, ideal]) => (countsByCategory[cat] || 0) < ideal)
                        .map(([cat]) => cat)
                );

                const filtered = itemsRes.data
                    .filter(i => missingCategories.has(i.category))
                    .slice(0, 3) // of 5, wat je wil

                    // Voeg hier eventueel dummy-beschrijvingen toe
                    .map(i => ({
                        name: i.name,
                        description: `Een ${i.category.toLowerCase()} die je menu kan versterken.`, // placeholder
                    }));

                setMenuItems(filtered);
            } catch (err) {
                console.error(err);
                setError("Kon aanbevelingen niet laden");
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error) return <p>{error}</p>;

    return (
        <HotTemplate
            title={title}
            subtitle={subtitle}
            menuItems={menuItems}
        />
    );
};

export default HotForYou;
